191	async function startRealDdxServer(fixtureRoot: string): Promise<RealServer> {
192		const port = await freePort();
193		const bin = ensureDdxBinary();
194		const child = spawn(bin, ['server', '--port', String(port), '--tsnet=false'], {
195			cwd: fixtureRoot,
196			env: {
197				...process.env,
198				DDX_NODE_NAME: 'graph-e2e-node',
199				XDG_DATA_HOME: path.join(fixtureRoot, '.xdg-data')
200			}
201		});
202		child.stdout.resume();
203		child.stderr.resume();
204		const baseURL = `https://127.0.0.1:${port}`;
205		const api = await playwrightRequest.newContext({ baseURL, ignoreHTTPSErrors: true });
206	
207		let lastError: unknown;
208		for (let i = 0; i < 80; i++) {
209			if (child.exitCode !== null) {
210				throw new Error(`ddx server exited early with code ${child.exitCode}`);
211			}
212			try {
213				const resp = await api.get('/api/health', { timeout: 500 });
214				if (resp.ok()) {
215					const infoResp = await api.post('/graphql', {
216						data: {
217							query: `query E2EProjectInfo {
218								nodeInfo { id name }
219								projects { edges { node { id name path } } }
220							}`
221						}
222					});
223					const payload = (await infoResp.json()) as {
224						data: {
225							nodeInfo: { id: string };
226							projects: { edges: Array<{ node: { id: string } }> };
227						};
228					};
229					const projectId = payload.data.projects.edges[0]?.node.id;
230					if (!projectId) throw new Error('ddx server returned no registered project');
231					return {
232						api,
233						nodeId: payload.data.nodeInfo.id,
234						projectId,
235						process: child,
236						root: fixtureRoot
237					};
238				}
239			} catch (err) {
240				lastError = err;
241			}
242			await new Promise((resolve) => setTimeout(resolve, 125));
243		}
244	
245		child.kill();
246		await api.dispose();
247		throw new Error(`ddx server did not become healthy: ${String(lastError)}`);
248	}
