521		const measure = (bg: [number, number, number]) =>
522			page.evaluate((bgRgb) => {
523				function parseRgb(s: string): [number, number, number, number] {
524					const m = s.match(/rgba?\(([^)]+)\)/i);
525					if (!m) return [0, 0, 0, 1];
526					const parts = m[1].split(',').map((p) => parseFloat(p.trim()));
527					return [parts[0], parts[1], parts[2], parts[3] === undefined ? 1 : parts[3]];
528				}
529				function blend(
530					fg: [number, number, number],
531					alpha: number,
532					bg: [number, number, number]
533				): [number, number, number] {
534					return [
535						fg[0] * alpha + bg[0] * (1 - alpha),
536						fg[1] * alpha + bg[1] * (1 - alpha),
537						fg[2] * alpha + bg[2] * (1 - alpha)
538					];
539				}
540				function chan(c: number) {
541					const v = c / 255;
542					return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
543				}
544				function lum([r, g, b]: [number, number, number]) {
545					return 0.2126 * chan(r) + 0.7152 * chan(g) + 0.0722 * chan(b);
546				}
547				function contrast(a: [number, number, number], b: [number, number, number]) {
548					const la = lum(a);
549					const lb = lum(b);
550					const [hi, lo] = la > lb ? [la, lb] : [lb, la];
551					return (hi + 0.05) / (lo + 0.05);
