566				const fill = parseRgb(arrowCs.fill);
567				const canvas = bgRgb as [number, number, number];
568	
569				const blendedStroke = blend(
570					[stroke[0], stroke[1], stroke[2]],
571					strokeOpacity,
572					canvas
573				);
574				return {
575					stroke: contrast(blendedStroke, canvas),
576					arrow: contrast([fill[0], fill[1], fill[2]], canvas),
577					strokeRgb: [stroke[0], stroke[1], stroke[2]],
578					fillRgb: [fill[0], fill[1], fill[2]]
