4625	func (s *Server) handleGraphQLQuery(w http.ResponseWriter, r *http.Request) {
4626		// Gate /graphql on the same localhost auth that protects every /api/*
4627		// handler. Without this, operators running `ddx server --addr 0.0.0.0`
4628		// ship an unauthenticated GraphQL endpoint serving bead data, worker
4629		// logs, mutations, and subscriptions. See opus final-gate review of
4630		// ddx-02d6142d and the scope line "isTrusted() is still the gatekeeper;
4631		// no auth bypass introduced".
4632		if !isTrusted(r) {
4633			writeJSON(w, http.StatusForbidden, map[string]string{"error": "graphql is localhost-only"})
4634			return
4635		}
4636		// Create gqlgen server with the DDX GraphQL schema
4637		gqlServer := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
4638			Resolvers: &ddxgraphql.Resolver{
4639				State:                              s.state,
4640				WorkingDir:                         s.WorkingDir,
4641				Workers:                            s.workers,
4642				BeadBus:                            s.beadHub,
4643				Actions:                            &workerDispatchAdapter{manager: s.workers},
4644				ExecLogs:                           &execLogAdapter{workingDir: s.WorkingDir},
4645				CoordMetrics:                       &coordMetricsAdapter{reg: s.workers.LandCoordinators},
4646				CSRFTokens:                         s.csrfTokens,
4647				OperatorPromptIdempotency:          s.operatorPromptIdempotency,
4648				OperatorPromptAutoApproveAllowlist: s.operatorPromptAutoApproveAllowlist,
4649			},
4650			Directives: ddxgraphql.DirectiveRoot{},
4651		}))
4652		// Plumb the originating *http.Request into the resolver context so
4653		// resolvers (e.g. operatorPromptSubmit) can validate the CSRF header
4654		// and capture the originating identity from headers tsnetMiddleware
4655		// injects (X-Tailscale-User / X-Tailscale-Node).
4656		r = r.WithContext(ddxgraphql.WithHTTPRequest(r.Context(), r))
4657		gqlServer.AddTransport(transport.POST{})
4658		gqlServer.AddTransport(transport.GET{})
4659		gqlServer.AddTransport(transport.Websocket{
4660			Upgrader: websocket.Upgrader{
4661				CheckOrigin: func(r *http.Request) bool { return true },
4662			},
4663			KeepAlivePingInterval: 30 * time.Second,
4664		})
4665	
4666		gqlServer.ServeHTTP(w, r)
4667	}
