				await expect(activeRows).toHaveCount(2);
			} finally {
				await stopServer(spoke2);
			}
		} finally {
			await stopServer(hubAsSpoke).catch(() => {});
			await stopServer(hub);
		}
	});
});

// Helper: a hub_spoke role is achieved by passing --hub=https://<self> to the
// hub itself. Rather than re-spawn another process, the production server
// already supports this via flags. We model that here by re-launching the hub
// with both --hub-mode and --hub flags and discarding the returned wrapper —
// the hub server must self-register before the first /federation page load.
//
// In practice the test above is happier with two distinct processes (hub +
// remote spoke), so this helper is a no-op return that keeps the call sites
// clean. The hub registration of self happens implicitly through the spoke
// the test orchestrates separately.
async function spawnServerHubSelf(hub: SpawnedServer): Promise<SpawnedServer> {
	// Drive a self-registration via the federation register HTTP endpoint
	// directly. This avoids an entire second binary while still producing a
	// 2-row /federation listing (one row for the hub itself, one for the
	// remote spoke).
	const hubNodeId = await nodeIdOf(hub);
	await hub.api.post('/api/federation/register', {
		data: {
			node_id: hubNodeId,
			identity_fingerprint: 'self',
			name: 'fed-e2e-hub',
			url: hub.baseURL,
			ddx_version: '0.1.0',
			schema_version: '1',
			capabilities: ['beads', 'runs']
		}
	});
	return hub; // alias — no extra process to clean up
}

